package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

/**
 * Tests that verify consistent parsing behavior across all platforms.
 * 
 * This addresses the issue where JVM and JS would allow omitting seconds when parsing
 * with ISO_DATE_TIME_OFFSET (e.g., "2024-03-19T17:50Z"), while Native would fail.
 * Per the documentation, specifying seconds is NOT optional, so all platforms
 * should consistently reject such strings.
 */
class InstantParsingConsistencyTest {

    @Test
    fun testParseWithSecondsSucceeds() {
        // Parsing with seconds should succeed on all platforms
        val instant = Instant.parse("2024-03-19T17:50:00Z")
        val expected = LocalDateTime(2024, 3, 19, 17, 50, 0).toInstant(TimeZone.UTC)
        assertEquals(expected, instant)
    }

    @Test
    fun testParseWithSecondsAndFractionSucceeds() {
        // Parsing with seconds and fraction should succeed
        val instant = Instant.parse("2024-03-19T17:50:30.123Z")
        val expected = LocalDateTime(2024, 3, 19, 17, 50, 30, 123000000).toInstant(TimeZone.UTC)
        assertEquals(expected, instant)
    }

    @Test
    fun testParseWithoutSecondsFails() {
        // Per ISO_DATE_TIME_OFFSET documentation: "specifying the seconds is *not* optional"
        // This should fail consistently on all platforms
        assertFailsWith<DateTimeFormatException> {
            Instant.parse("2024-03-19T17:50Z")
        }
    }

    @Test
    fun testParseWithOffset() {
        // Parsing with various offsets should work
        val instant1 = Instant.parse("2024-03-19T17:50:00+00:00")
        val instant2 = Instant.parse("2024-03-19T17:50:00Z")
        assertEquals(instant1, instant2)

        val instant3 = Instant.parse("2024-03-19T18:50:00+01:00")
        assertEquals(instant1, instant3)

        // Offset without minutes (per documentation: "specifying the minutes is optional")
        val instant4 = Instant.parse("2024-03-19T18:50:00+01")
        assertEquals(instant1, instant4)
    }

    @Test
    fun testParseWithLowercaseT() {
        // Lowercase 't' should be accepted
        val instant1 = Instant.parse("2024-03-19T17:50:00Z")
        val instant2 = Instant.parse("2024-03-19t17:50:00Z")
        assertEquals(instant1, instant2)
    }

    @Test
    fun testParseWithLowercaseZ() {
        // Lowercase 'z' should be accepted
        val instant1 = Instant.parse("2024-03-19T17:50:00Z")
        val instant2 = Instant.parse("2024-03-19T17:50:00z")
        assertEquals(instant1, instant2)
    }
}
